#include <Wire.h>
#include <PCF8575.h>

// 创建PCF8575实例并设置其I2C地址
PCF8575 pcf8575_1(0x20); // 假设第一个PCF8575的I2C地址是0x20
PCF8575 pcf8575_2(0x21); // 假设第二个PCF8575的I2C地址是0x21

void setup() {
  Wire.begin(); // 启动I2C总线

  // 使用正确的库进行初始化可能不需要.begin()调用，但请检查您所使用的库文档来确认
  pcf8575_1.begin();
  pcf8575_2.begin();

  // 根据库的实现，您也可能需要初始化所有的引脚为低电平
  // 这可能会防止上电时未预料的高电平状态
  for (int i = 0; i < 16; i++) {
    pcf8575_1.digitalWrite(i, LOW);
    pcf8575_2.digitalWrite(i, LOW);
  }
}

void loop() {
  // 在loop中，您可以根据需要来控制各个引脚
  // 例如，将第一个扩展器的P0设置为高电平
  pcf8575_1.digitalWrite(P0, HIGH);
